
-- 1. Fix length taxonomy: add s6m, s65m, s7m entries
UPDATE home_content
SET data = jsonb_build_object('items', (
  SELECT jsonb_agg(item)
  FROM (
    SELECT item FROM jsonb_array_elements(data->'items') item
    UNION ALL
    SELECT '{"id":"s6m","value":"6M","label_he":"6 מטר","label_ar":"6 متر"}'::jsonb WHERE NOT EXISTS (SELECT 1 FROM jsonb_array_elements((SELECT data->'items' FROM home_content WHERE locale='global' AND section='length_taxonomy')) x WHERE x->>'id'='s6m')
    UNION ALL
    SELECT '{"id":"s65m","value":"6.5M","label_he":"6.5 מטר","label_ar":"6.5 متر"}'::jsonb WHERE NOT EXISTS (SELECT 1 FROM jsonb_array_elements((SELECT data->'items' FROM home_content WHERE locale='global' AND section='length_taxonomy')) x WHERE x->>'id'='s65m')
    UNION ALL
    SELECT '{"id":"s7m","value":"7M","label_he":"7 מטר","label_ar":"7 متر"}'::jsonb WHERE NOT EXISTS (SELECT 1 FROM jsonb_array_elements((SELECT data->'items' FROM home_content WHERE locale='global' AND section='length_taxonomy')) x WHERE x->>'id'='s7m')
  ) sub
))
WHERE locale = 'global' AND section = 'length_taxonomy';

