-- 3. Update content_html for HE translations
UPDATE product_translations SET content_html = '<div class="space-y-6"><div class="bg-gray-50 rounded-xl p-6"><h3 class="text-lg font-bold mb-3">מפרט טכני</h3><p>פרופיל אלומיניום מסדרה 2000 של AMG Pergola. מיוצר מאלומיניום 6063-T5 באיכות פרימיום, מתאים לשימוש חיצוני בתנאי מזג אוויר קשים. הפרופיל עובר תהליך אנודייז או צביעה אלקטרוסטטית להגנה מירבית מפני קורוזיה.</p></div><div class="bg-gray-50 rounded-xl p-6"><h3 class="text-lg font-bold mb-3">יתרונות</h3><ul class="list-disc list-inside space-y-2 text-gray-700"><li>עמידות גבוהה בפני קורוזיה ושחיקה</li><li>משקל קל יחסית לחוזק המכני</li><li>מגוון צבעים וגימורים זמינים</li><li>התקנה פשוטה ומהירה</li><li>אחריות יצרן למשך 10 שנים</li><li>תחזוקה מינימלית</li></ul></div><div class="bg-gray-50 rounded-xl p-6"><h3 class="text-lg font-bold mb-3">הנחיות התקנה</h3><p>יש לבצע חיתוך באמצעות מסור דיסק עם להב מתאים לאלומיניום. מומלץ להשתמש בברגי נירוסטה למניעת קורוזיה גלוונית. יש להקפיד על מרווחי התפשטות תרמית בהתאם להנחיות היצרן.</p></div></div>'
WHERE locale = 'he' AND product_id IN (SELECT id FROM products WHERE category_id = '8807c168-cfd0-47a1-9b00-42f16b2fc9f5');

-- 4. Update content_html for AR translations
UPDATE product_translations SET content_html = '<div class="space-y-6"><div class="bg-gray-50 rounded-xl p-6"><h3 class="text-lg font-bold mb-3">المواصفات التقنية</h3><p>بروفيل ألمنيوم من سلسلة 2000 من AMG Pergola. مصنوع من ألمنيوم 6063-T5 بجودة ممتازة، مناسب للاستخدام الخارجي في ظروف مناخية قاسية. يخضع البروفيل لعملية أنودة أو طلاء إلكتروستاتيكي لحماية قصوى من التآكل.</p></div><div class="bg-gray-50 rounded-xl p-6"><h3 class="text-lg font-bold mb-3">المميزات</h3><ul class="list-disc list-inside space-y-2 text-gray-700"><li>مقاومة عالية للتآكل والتلف</li><li>وزن خفيف نسبياً مقارنة بالمتانة الميكانيكية</li><li>مجموعة متنوعة من الألوان والتشطيبات المتاحة</li><li>تركيب سهل وسريع</li><li>ضمان المصنع لمدة 10 سنوات</li><li>صيانة بسيطة</li></ul></div><div class="bg-gray-50 rounded-xl p-6"><h3 class="text-lg font-bold mb-3">تعليمات التركيب</h3><p>يجب القطع باستخدام منشار قرصي بشفرة مناسبة للألمنيوم. يوصى باستخدام براغي من الفولاذ المقاوم للصدأ لمنع التآكل الجلفاني. يجب مراعاة فجوات التمدد الحراري وفقاً لتعليمات الشركة المصنعة.</p></div></div>'
WHERE locale = 'ar' AND product_id IN (SELECT id FROM products WHERE category_id = '8807c168-cfd0-47a1-9b00-42f16b2fc9f5');
